sed -i 's/if d\&ShellCompDirectiveKeepOrder != 0 {/if d\&ShellCompDirectiveNoDescription != 0 {
		directives = append(directives, "ShellCompDirectiveNoDescription")
	}
	if d\&ShellCompDirectiveKeepOrder != 0 {/' /workspace/repo/completions.go

python3 << 'EOF'
# Read the file
with open('/workspace/repo/completions.go', 'r') as f:
    content = f.read()

# 1. Mark GetFlagCompletion as deprecated
old_get_flag_completion = '''// GetFlagCompletion returns the completion function for the given flag, if available.
func GetFlagCompletion(flag *pflag.Flag) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
\tflagCompletionMutex.RLock()
\tdefer flagCompletionMutex.RUnlock()

\tcompletionFunc, exists := flagCompletionFunctions[flag]
\treturn completionFunc, exists
}'''

new_get_flag_completion = '''// GetFlagCompletion returns the completion function for the given flag, if available.
// Deprecated: Use Command.GetFlagCompletionFunc instead.
func GetFlagCompletion(flag *pflag.Flag) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
\tflagCompletionMutex.RLock()
\tdefer flagCompletionMutex.RUnlock()

\tcompletionFunc, exists := flagCompletionFunctions[flag]
\treturn completionFunc, exists
}'''

content = content.replace(old_get_flag_completion, new_get_flag_completion)

# 2. Update GetFlagCompletionByName to use c.Flag(flagName)
old_get_flag_completion_by_name = '''// GetFlagCompletionByName returns the completion function for the given flag in the command by name, if available.
func (c *Command) GetFlagCompletionByName(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
\tflag := c.Flags().Lookup(flagName)
\tif flag == nil {
\t\treturn nil, false
\t}

\treturn GetFlagCompletion(flag)
}'''

new_get_flag_completion_by_name = '''// GetFlagCompletionByName returns the completion function for the given flag in the command by name, if available.
// Deprecated: Use Command.GetFlagCompletionFunc instead.
func (c *Command) GetFlagCompletionByName(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
\tflag := c.Flags().Lookup(flagName)
\tif flag == nil {
\t\treturn nil, false
\t}

\treturn GetFlagCompletion(flag)
}

// GetFlagCompletionFunc returns the completion function for the given flag, if available.
// It uses c.Flag(flagName) which searches for both local and persistent flags,
// allowing it to correctly resolve flags defined on parent commands.
func (c *Command) GetFlagCompletionFunc(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
\tflag := c.Flag(flagName)
\tif flag == nil {
\t\treturn nil, false
\t}

\tflagCompletionMutex.RLock()
\tdefer flagCompletionMutex.RUnlock()

\tcompletionFunc, exists := flagCompletionFunctions[flag]
\treturn completionFunc, exists
}'''

content = content.replace(old_get_flag_completion_by_name, new_get_flag_completion_by_name)

# Write the file back
with open('/workspace/repo/completions.go', 'w') as f:
    f.write(content)

print("Changes applied successfully!")
EOF
